@dataclass
class Vector2:
    x: float = 0.0
    y: float = 0.0

    def distance_to(self, other: 'Vector2') -> float:
        return math.sqrt((self.x - other.x) ** 2 + (self.y - other.y) ** 2)

    def to_dict(self):
        return {"x": self.x, "y": self.y}

    @staticmethod
    def from_dict(d):
        return Vector2(x=d.get("x", 0), y=d.get("y", 0))


@dataclass
class Obstacle:
    position: Vector2
    width: float
    height: float
    obstacle_type: str = "wall"
    destructible: bool = False
    health: float = 100.0
    obstacle_id: str = field(default_factory=lambda: str(uuid.uuid4())[:8])

    def to_dict(self):
        return {
            "id": self.obstacle_id,
            "position": self.position.to_dict(),
            "width": self.width,
            "height": self.height,
            "type": self.obstacle_type,
            "destructible": self.destructible,
            "health": self.health,
        }

    def get_corners(self) -> List[Tuple[float, float]]:
        px, py = self.position.x, self.position.y
        hw, hh = self.width / 2, self.height / 2
        return [
            (px - hw, py - hh),
            (px + hw, py - hh),
            (px + hw, py + hh),
            (px - hw, py + hh),
        ]

    def contains_point(self, x: float, y: float) -> bool:
        hw, hh = self.width / 2, self.height / 2
        return (self.position.x - hw <= x <= self.position.x + hw and
                self.position.y - hh <= y <= self.position.y + hh)


