class GameMap:
    def __init__(self, width: float = 2000, height: float = 2000):
        self.width = width
        self.height = height
        self.obstacles: List[Obstacle] = []
        self.loot_items: Dict[str, LootItem] = {}
        self._generate_map()

    def _generate_map(self):
        random.seed(42)

        # Generate buildings (clusters of walls)
        building_positions = [
            (300, 300), (700, 200), (1200, 400), (1600, 300),
            (200, 800), (600, 700), (1000, 600), (1400, 800),
            (400, 1200), (800, 1100), (1200, 1200), (1700, 1100),
            (300, 1600), (900, 1500), (1500, 1600), (1000, 1000),
        ]

        for bx, by in building_positions:
            size = random.uniform(40, 100)
            # Create walls for each building
            wall_thickness = 5
            # Top wall
            self.obstacles.append(Obstacle(
                position=Vector2(bx, by - size / 2),
                width=size, height=wall_thickness,
                obstacle_type="wall", destructible=True, health=200
            ))
            # Bottom wall
            self.obstacles.append(Obstacle(
                position=Vector2(bx, by + size / 2),
                width=size, height=wall_thickness,
                obstacle_type="wall", destructible=True, health=200
            ))
            # Left wall
            self.obstacles.append(Obstacle(
                position=Vector2(bx - size / 2, by),
                width=wall_thickness, height=size,
                obstacle_type="wall", destructible=True, health=200
            ))
            # Right wall (with gap for door)
            self.obstacles.append(Obstacle(
                position=Vector2(bx + size / 2, by - size / 4),
                width=wall_thickness, height=size / 2,
                obstacle_type="wall", destructible=True, health=200
            ))

        # Scatter rocks and trees
        for _ in range(80):
            x = random.uniform(50, self.width - 50)
            y = random.uniform(50, self.height - 50)
            obs_type = random.choice(["rock", "tree", "crate"])
            size = random.uniform(8, 25)
            self.obstacles.append(Obstacle(
                position=Vector2(x, y),
                width=size, height=size,
                obstacle_type=obs_type,
                destructible=obs_type == "crate",
                health=50 if obs_type == "crate" else 999
            ))

        # Generate loot
        loot_types = [
            ("weapon", "shotgun"), ("weapon", "assault_rifle"),
            ("weapon", "sniper"), ("weapon", "smg"),
            ("ammo", "pistol_ammo"), ("ammo", "shotgun_ammo"),
            ("ammo", "rifle_ammo"), ("ammo", "sniper_ammo"),
            ("health", "medkit"), ("health", "bandage"),
            ("armor", "light_armor"), ("armor", "heavy_armor"),
        ]

        for _ in range(200):
            x = random.uniform(50, self.width - 50)
            y = random.uniform(50, self.height - 50)
            ltype, lname = random.choice(loot_types)
            qty = 1 if ltype == "weapon" else random.randint(1, 3)
            item = LootItem(
                item_id=str(uuid.uuid4())[:8],
                position=Vector2(x, y),
                item_type=ltype,
                item_name=lname,
                quantity=qty,
            )
            self.loot_items[item.item_id] = item

    def line_of_sight(self, p1: Vector2, p2: Vector2) -> bool:
        """Check if there's a clear line of sight between two points using ray casting."""
        dx = p2.x - p1.x
        dy = p2.y - p1.y
        dist = math.sqrt(dx * dx + dy * dy)
        if dist == 0:
            return True

        steps = max(int(dist / 5), 1)
        step_x = dx / steps
        step_y = dy / steps

        for i in range(1, steps):
            check_x = p1.x + step_x * i
            check_y = p1.y + step_y * i
            for obs in self.obstacles:
                if obs.contains_point(check_x, check_y):
                    return False
        return True

    def to_dict(self):
        return {
            "width": self.width,
            "height": self.height,
            "obstacles": [o.to_dict() for o in self.obstacles],
        }


